const userMessage =
  $json.chatInput ||
  $json.message ||
  $json.text ||
  "";

// Internship start date
const internshipStartDate = new Date("2026-02-02"); // Day 1

let dayNumber = null;

/*
CASE 1 → Input like "Day 7"
*/
const explicitDayMatch = userMessage.match(/day\s*(\d+)/i);

if (explicitDayMatch) {
  dayNumber = parseInt(explicitDayMatch[1]);
}

/*
CASE 2 → Input like "10 Feb 2026"
*/
else {
  const inputDate = new Date(userMessage);

  if (!isNaN(inputDate)) {
    let currentDate = new Date(internshipStartDate);
    let workingDayCount = 1;

    // move forward until dates match
    while (currentDate.toDateString() !== inputDate.toDateString()) {
      currentDate.setDate(currentDate.getDate() + 1);

      const dayOfWeek = currentDate.getDay();

      // Skip Saturday (6) + Sunday (0)
      if (dayOfWeek !== 0 && dayOfWeek !== 6) {
        workingDayCount++;
      }

      if (workingDayCount > 200) break;
    }

    dayNumber = workingDayCount;
  }
}

/*
Validation
*/
if (!dayNumber || dayNumber < 1 || dayNumber > 60) {
  return [
    {
      json: {
        error: "Please enter like: Day 7 or 10 Feb 2026"
      }
    }
  ];
}

/*
Generate exact VTU date from dayNumber
*/
let targetDate = new Date(internshipStartDate);
let counter = 1;

while (counter < dayNumber) {
  targetDate.setDate(targetDate.getDate() + 1);

  const dayOfWeek = targetDate.getDay();

  if (dayOfWeek !== 0 && dayOfWeek !== 6) {
    counter++;
  }
}

const vtuDate = targetDate.toISOString().split("T")[0];

/*
Phase → Week → Day mapping
*/
const phase = Math.ceil(dayNumber / 20);

const dayInsidePhase = ((dayNumber - 1) % 20) + 1;

const week = Math.ceil(dayInsidePhase / 5);

const day = ((dayInsidePhase - 1) % 5) + 1;

return [
  {
    json: {
      originalMessage: userMessage,
      dayNumber,
      vtuDate,
      phase,
      week,
      day
    }
  }
];

const dayNumber = $json.dayNumber;

// Internship start date = Day 1
const internshipStartDate = new Date("2026-02-02");

// Create working-day based VTU date
let workingDayCount = 1;
let targetDate = new Date(internshipStartDate);

while (workingDayCount < dayNumber) {
  targetDate.setDate(targetDate.getDate() + 1);

  const dayOfWeek = targetDate.getDay();

  // Skip Saturday (6) and Sunday (0)
  if (dayOfWeek !== 0 && dayOfWeek !== 6) {
    workingDayCount++;
  }
}

// Format YYYY-MM-DD
const formattedDate = targetDate.toISOString().split("T")[0];

// Phase calculation
const phase = Math.ceil(dayNumber / 20);

// Day inside phase (1–20)
const dayInsidePhase = ((dayNumber - 1) % 20) + 1;

// Week calculation
const week = Math.ceil(dayInsidePhase / 5);

// Day inside week (1–5)
const weekDay = ((dayInsidePhase - 1) % 5) + 1;

return [
  {
    json: {
      dayNumber,
      vtuDate: formattedDate,
      phase,
      week,
      day: weekDay
    }
  }
];

const targetPhase = $node["Curriculum API"].json.phase;
const targetWeek = $node["Curriculum API"].json.week;
const targetDay = $node["Curriculum API"].json.day;

/*
Get actual HTTP response from previous Curriculum API node
Sometimes n8n gives object directly,
sometimes inside array/object wrappers
*/
let curriculum = $input.first().json;

// If wrapped inside "data"
if (curriculum.data) {
  curriculum = curriculum.data;
}

// If wrapped inside "curriculum"
if (curriculum.curriculum) {
  curriculum = curriculum.curriculum;
}

// Force into array if single object
if (!Array.isArray(curriculum)) {
  curriculum = [curriculum];
}

/*
Find correct phase
*/
const selectedPhase = curriculum.find(
  item => Number(item.order) === Number(targetPhase)
);

if (!selectedPhase) {
  throw new Error("Phase not found");
}

/*
Find correct week
*/
if (!selectedPhase.weeks || !Array.isArray(selectedPhase.weeks)) {
  throw new Error("Weeks not found inside selected phase");
}

const selectedWeek = selectedPhase.weeks.find(
  item => Number(item.order) === Number(targetWeek)
);

if (!selectedWeek) {
  throw new Error("Week not found");
}

/*
Find correct day
*/
if (!selectedWeek.days || !Array.isArray(selectedWeek.days)) {
  throw new Error("Days not found inside selected week");
}

const selectedDay = selectedWeek.days.find(
  item => Number(item.order) === Number(targetDay)
);

if (!selectedDay) {
  throw new Error("Day not found");
}

/*
Get first lesson
*/
if (!selectedDay.lessons || !Array.isArray(selectedDay.lessons) || selectedDay.lessons.length === 0) {
  throw new Error("Lesson not found");
}

const lesson = selectedDay.lessons[0];

return [
  {
    json: {
      phase: targetPhase,
      week: targetWeek,
      day: targetDay,
      lessonId: lesson.lessonId,
      lessonTitle: lesson.title
    }
  }
];
